SELECT [Purchase Header].[Buy-from Vendor No_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Purchase Line].No_ AS Article, Item.[Description 2] AS Description, [Purchase Line].[Constant Variable Code] AS Color, [Purchase Line].[Assortment Code], [Purchase Header].[Document Type], Sum(Val([Purchase Line.No_ of Pairs])) AS PairsPurchased, Sum(IIf(Val([Purchase Line.quantity])>0,Val([Purchase Line.quantity received])/Val([Purchase Line.quantity])*Val([Purchase Line.no_ of pairs]),0)) AS PairsReceived, Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name AS ManufacturerName
FROM ((([Purchase Header] INNER JOIN [Purchase Line] ON ([Purchase Header].No_ = [Purchase Line].[Document No_]) AND ([Purchase Header].[Document Type] = [Purchase Line].[Document Type])) INNER JOIN Item ON [Purchase Line].No_ = Item.No_) INNER JOIN Vendor ON [Purchase Header].[Buy-from Vendor No_] = Vendor.No_) LEFT JOIN Vendor AS Vendor_1 ON Item.Manufacturer = Vendor_1.No_
GROUP BY [Purchase Header].[Buy-from Vendor No_], Vendor.Name, Item.[Trademark Code], Item.[Season Code], Item.[Line Code], Item.[Collection Code], Item.[Product Sex], [Purchase Line].No_, Item.[Description 2], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Header].[Document Type], [Purchase Line].[Delete Reason], [Purchase Line].Type, Item.[Advertising Material], Item.Manufacturer, Vendor_1.Name
HAVING ((([Purchase Header].[Document Type])=1) AND (([Purchase Line].[Delete Reason])="") AND (([Purchase Line].Type)=19 Or ([Purchase Line].Type)=20) AND ((Item.[Advertising Material])=0));

